function DailyDigest() {
  const [city, setCity] = React.useState('REPLACE_WITH_CITY');
  const [text, setText] = React.useState('');
  const [loading, setLoading] = React.useState(false);
  const [autoTime, setAutoTime] = React.useState('07:00');
  const compile = async () => {
    setLoading(true);
    try {
      const r = await titan.api.call('/api/message', { method: 'POST', body: { content: `Compile my daily briefing for ${new Date().toLocaleDateString()}.\n\nInclude: weather in ${city}, today's calendar, unread email count, top 3 news headlines, BTC + ETH price. Tone: warm, concise, like a good morning text from a thoughtful assistant. Plain text only, no markdown.` } });
      setText(r?.content || r?.text || JSON.stringify(r));
    } catch (e) { setText('Error: ' + (e?.message||e)); }
    finally { setLoading(false); }
  };
  React.useEffect(() => {
    const check = () => {
      const now = new Date();
      const hh = String(now.getHours()).padStart(2,'0');
      const mm = String(now.getMinutes()).padStart(2,'0');
      if (`${hh}:${mm}` === autoTime) compile();
    };
    const id = setInterval(check, 60000);
    return () => clearInterval(id);
  }, [autoTime, city]);
  return (
    <div style={{padding:14,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:10}}>
      <div style={{display:'flex',gap:6}}>
        <input value={city} onChange={e=>setCity(e.target.value)} placeholder="City" style={{flex:1,padding:'6px 10px',border:'1px solid #ccc',borderRadius:6,fontSize:13}}/>
        <input type="time" value={autoTime} onChange={e=>setAutoTime(e.target.value)} style={{padding:'6px 10px',border:'1px solid #ccc',borderRadius:6,fontSize:13}}/>
        <button onClick={compile} disabled={loading} style={{padding:'6px 14px',border:'none',borderRadius:6,background:'#007AFF',color:'#fff',cursor:loading?'wait':'pointer',fontWeight:600}}>{loading?'Compiling…':'Run Now'}</button>
      </div>
      <div style={{fontSize:11,color:'#888'}}>Auto-runs at {autoTime} local. Manual run anytime.</div>
      <div style={{flex:1,overflow:'auto',padding:14,background:'linear-gradient(135deg,#FFF7E6,#FFE4D4)',borderRadius:12,fontSize:14,lineHeight:1.6,whiteSpace:'pre-wrap'}}>
        {loading ? '✨ Composing your briefing…' : (text || `Tap Run Now to generate your morning briefing.`)}
      </div>
    </div>
  );
}
render(<DailyDigest/>);
